ee:message.ee:set-payload:
%dw 2.0
output application/json
---
{
    success: true,
    data: {
        orderId: vars.orderId,
        status: "FULFILLING",
        pickingId: vars.pickingResponse.pickingId default "",
        warehouseId: vars.fulfillmentRequest.warehouseId default "WH-PRIMARY",
        shippingMethod: vars.fulfillmentRequest.shippingMethod default "STANDARD",
        estimatedShipDate: vars.pickingResponse.estimatedShipDate default ((now() + |P1D|) as String {format: "yyyy-MM-dd"}),
        estimatedDeliveryDate: vars.pickingResponse.estimatedDeliveryDate default ((now() + |P5D|) as String {format: "yyyy-MM-dd"}),
        paymentStatus: vars.paymentStatus.status default "VERIFIED",
        fulfillmentInitiatedAt: now() as String {format: "yyyy-MM-dd'T'HH:mm:ss.SSSZ"}
    },
    correlationId: correlationId,
    timestamp: now() as String {format: "yyyy-MM-dd'T'HH:mm:ss.SSSZ"}
}
